const { FILE_OWNERS } = require('../../constants/file');
const {
  INDEX_VIEW_FILE_REGEX,
  INDEX_STYLE_SHEET_FILE_REGEX,
  FILE_EXTENSION_REGEX,
  FOLDER_WITH_PARAMS_REGEX,
  FILE_WITH_PARAMS_REGEX,
  FOLDER_WITH_CATCH_ALL_REGEX,
  FILE_WITH_CATCH_ALL_REGEX,
} = require('../../constants/regexs');
const { getFileOwner } = require('./owner');
const {
  getFileDetail,
  checkIfFileHasParams,
  checkIfFileHasCatchAll,
  getPathSegmentsWithoutIndex,
} = require('./path-detail');

const fileOwnersOrder = [
  FILE_OWNERS.httpErrorPage,
  FILE_OWNERS.baseHooks,
  FILE_OWNERS.routerConfig,
];

/**
 * @param {boolean} aIsCatchAll
 * @param {boolean} bIsCatchAll
 * @returns {1|-1|0}
 */
const getCatchAllComparison = (aIsCatchAll, bIsCatchAll) => {
  if (!aIsCatchAll && bIsCatchAll) {
    return -1;
  }

  if (aIsCatchAll && !bIsCatchAll) {
    return 1;
  }

  return 0;
};

/**
 * @param {boolean} aIsCatchAll
 * @param {boolean} bIsCatchAll
 * @param {boolean} aIsParam
 * @param {boolean} bIsParam
 * @returns {1|-1|0}
 */
const getParamComparison = (aIsCatchAll, bIsCatchAll, aIsParam, bIsParam) => {
  if (!aIsParam && !aIsCatchAll && bIsParam) {
    return -1;
  }

  if (aIsParam && !bIsParam && !bIsCatchAll) {
    return 1;
  }

  return 0;
};

/**
 * @param {number} index
 * @param {number} segmentsLength
 * @param {RegExp} folderRegex
 * @param {RegExp} fileRegex
 * @param {string} aSegment
 * @param {string} bSegment
 */
const getSegmentRegex = (
  index,
  segmentsLength,
  folderRegex,
  fileRegex,
  aSegment,
  bSegment,
) => {
  const isLastSegment = index === segmentsLength - 1;

  return {
    aRegex:
      isLastSegment && FILE_EXTENSION_REGEX.test(aSegment)
        ? fileRegex
        : folderRegex,
    bRegex:
      isLastSegment && FILE_EXTENSION_REGEX.test(bSegment)
        ? fileRegex
        : folderRegex,
  };
};

/**
 * @param {string} aFile
 * @param {string} bFile
 * @returns {1|-1|0}
 */
const compareFileSegmentsWithParamsOrCatchAll = (aFile, bFile) => {
  const aSegments = getPathSegmentsWithoutIndex(aFile);
  const bSegments = getPathSegmentsWithoutIndex(bFile);

  if (aSegments.length !== bSegments.length) {
    return aSegments.length > bSegments.length ? -1 : 1;
  }

  let result = 0;

  for (let i = 0; i < aSegments.length; i += 1) {
    const aSegment = aSegments[i];
    const bSegment = bSegments[i];

    const { aRegex: aCatchAllRegex, bRegex: bCatchAllRegex } = getSegmentRegex(
      i,
      aSegments.length,
      FOLDER_WITH_CATCH_ALL_REGEX,
      FILE_WITH_CATCH_ALL_REGEX,
      aSegment,
      bSegment,
    );

    const { aRegex: aParamsRegex, bRegex: bParamsRegex } = getSegmentRegex(
      i,
      aSegments.length,
      FOLDER_WITH_PARAMS_REGEX,
      FILE_WITH_PARAMS_REGEX,
      aSegment,
      bSegment,
    );

    const aIsCatchAll = aCatchAllRegex.test(aSegment);
    const bIsCatchAll = bCatchAllRegex.test(bSegment);
    const aIsParam = aParamsRegex.test(aSegment) && !aIsCatchAll;
    const bIsParam = bParamsRegex.test(bSegment) && !bIsCatchAll;

    result =
      getParamComparison(aIsCatchAll, bIsCatchAll, aIsParam, bIsParam) ||
      getCatchAllComparison(aIsCatchAll, bIsCatchAll, aIsParam, bIsParam);

    if (result) {
      break;
    }
  }

  return result;
};

/**
 * Returns:
 * - "1" if aFile's owner has priority over bFile's owner
 * - "-1" if bFile's owner has priority over aFile's owner
 * - "0" if both files belong to the same owner
 * @param {string} aFile
 * @param {string} bFile
 * @returns {1|-1|0}
 */
const compareFileOwner = (aFile, bFile) => {
  const aOrder = fileOwnersOrder.indexOf(getFileOwner(aFile));
  const bOrder = fileOwnersOrder.indexOf(getFileOwner(bFile));

  if (aOrder < bOrder) {
    return 1;
  }

  if (aOrder > bOrder) {
    return -1;
  }

  return 0;
};

/**
 * Returns:
 * - "1" if bFile has index naming convention and is located in the app/nordic-pages root and aFile does not
 * - "-1" if aFile has index naming convention and is located in the app/nordic-pages root and bFile does not
 * - "1" if both, aFile and bFile, have index naming convention and are located in the app/nordic-pages root
 * @param {string} aFile
 * @param {string} bFile
 * @returns {1|-1|0}
 */
const compareIndexFiles = (aFile, bFile) => {
  const isIndexFile = (file) =>
    INDEX_VIEW_FILE_REGEX.test(file) || INDEX_STYLE_SHEET_FILE_REGEX.test(file);

  const aIsIndex = isIndexFile(aFile);
  const bIsIndex = isIndexFile(bFile);

  if (aIsIndex && !bIsIndex) {
    return -1;
  }

  if (!aIsIndex && bIsIndex) {
    return 1;
  }

  return 0;
};

/**
 * Returns:
 * - "1" if aFile has any params or catch-all and bFile has no params or catch-all
 * - "-1" if bFile has any params or catch-all and aFile has no params or catch-all
 * - "0" if both, aFile and bFile, have any params or catch-all
 * @param {string} aFile
 * @param {string} bFile
 * @returns {1|-1|0}
 */
const compareFileWithParamsOrCatchAll = (aFile, bFile) => {
  const aHasParamsOrCatchAll =
    checkIfFileHasParams(aFile) || checkIfFileHasCatchAll(aFile);
  const bHasParamsOrCatchAll =
    checkIfFileHasParams(bFile) || checkIfFileHasCatchAll(bFile);

  if (!aHasParamsOrCatchAll && bHasParamsOrCatchAll) {
    return -1;
  }

  if (aHasParamsOrCatchAll && !bHasParamsOrCatchAll) {
    return 1;
  }

  return compareFileSegmentsWithParamsOrCatchAll(aFile, bFile);
};

/**
 * Compare two file paths to finally sort the list of
 * discovered files from the most specific to the least specific.
 * The expected order is:
 *    - First, base hooks files
 *    - Second, http error files
 *    - Third, specific files
 * @param { string } a - File path positioned immediately before 'b'.
 * @param { string } b - File path positioned immediately after 'a'.
 * @returns { number } When:
 * - '-1': Indicates that 'a' has to be after 'b'
 * - '1': Indicates that 'a' has to be before 'b'
 */
const compareToSortFilesByOwnerAndPage = (a, b) => {
  const ownerComparison = compareFileOwner(a, b);

  if (ownerComparison !== 0) {
    return ownerComparison;
  }

  const indexComparison = compareIndexFiles(a, b);

  if (indexComparison !== 0) {
    return indexComparison;
  }

  const withParamsOrCatchAllComparison = compareFileWithParamsOrCatchAll(a, b);

  if (withParamsOrCatchAllComparison !== 0) {
    return withParamsOrCatchAllComparison;
  }

  const aFileDetail = getFileDetail(a);
  const bFileDetail = getFileDetail(b);

  const dirComparison = aFileDetail.dirname.localeCompare(bFileDetail.dirname);

  if (dirComparison !== 0) {
    const dirWithParamsOrCatchAllComparison = compareFileWithParamsOrCatchAll(
      aFileDetail.dirname,
      bFileDetail.dirname,
    );

    if (dirWithParamsOrCatchAllComparison !== 0) {
      return dirWithParamsOrCatchAllComparison;
    }

    return dirComparison;
  }

  const baseComparison = aFileDetail.basename.localeCompare(
    bFileDetail.basename,
  );

  if (baseComparison !== 0) {
    const basenameWithParamsOrCatchAllComparison =
      compareFileWithParamsOrCatchAll(
        aFileDetail.basename,
        bFileDetail.basename,
      );

    if (basenameWithParamsOrCatchAllComparison !== 0) {
      return basenameWithParamsOrCatchAllComparison;
    }

    return baseComparison;
  }

  return aFileDetail.deviceType.localeCompare(bFileDetail.deviceType);
};

module.exports = {
  compareFileOwner,
  compareToSortFilesByOwnerAndPage,
};
